--- packages/ui/src/engine/pixel-characters.ts	2024-06-10 00:00:00.000000000 +0000
+++ packages/ui/src/engine/pixel-characters.ts	2024-06-10 00:00:00.000000000 +0000
@@ 2172,0 +2172,111 @@
+// ─── Castle overview floor plan rendering ─────────────────────────
+
+interface Room {
+  id: string;
+  type: CharacterType;
+  x: number; // top-left corner x in layout units
+  y: number; // top-left corner y in layout units
+  w: number; // width in layout units
+  h: number; // height in layout units
+}
+
+interface Doorway {
+  x: number;
+  y: number;
+  width: number;
+  height: number;
+}
+
+interface Corridor {
+  x: number;
+  y: number;
+  w: number;
+  h: number;
+}
+
+/**
+ * Draw a unified castle floor plan overview showing all rooms connected by corridors.
+ * Rooms are drawn as rectangles with labels, corridors connect adjacent rooms,
+ * and doorways are drawn between rooms on shared edges.
+ * @param ctx CanvasRenderingContext2D
+ * @param rooms Array of rooms with layout positions and sizes
+ * @param scale Scale factor for drawing
+ */
+export function drawCastleOverview(ctx: CanvasRenderingContext2D, rooms: Room[], scale: number) {
+  // Clear background
+  ctx.fillStyle = '#222222';
+  ctx.fillRect(0, 0, ctx.canvas.width, ctx.canvas.height);
+
+  // Draw rooms
+  ctx.lineWidth = 2;
+  ctx.font = `${12 * scale}px monospace`;
+  ctx.textAlign = 'center';
+  ctx.textBaseline = 'middle';
+
+  // Map room id to room for adjacency checks
+  const roomMap = new Map<string, Room>();
+  for (const r of rooms) roomMap.set(r.id, r);
+
+  // Draw corridors and doorways between adjacent rooms
+  const corridors: Corridor[] = [];
+  const doorways: Doorway[] = [];
+
+  // Helper to check adjacency and create corridor & doorways
+  function connectRooms(r1: Room, r2: Room) {
+    // Check horizontal adjacency (r1 right edge == r2 left edge)
+    if (Math.abs(r1.x + r1.w - r2.x) < 0.01) {
+      // Vertical overlap
+      const overlapTop = Math.max(r1.y, r2.y);
+      const overlapBottom = Math.min(r1.y + r1.h, r2.y + r2.h);
+      if (overlapBottom > overlapTop) {
+        const corridorX = r1.x + r1.w;
+        const corridorY = overlapTop;
+        const corridorW = scale * 8; // corridor width fixed
+        const corridorH = (overlapBottom - overlapTop) * scale;
+        corridors.push({ x: corridorX * scale, y: corridorY * scale, w: corridorW, h: corridorH });
+        // Doorways on both rooms at corridor connection
+        const doorHeight = Math.min(12 * scale, corridorH * 0.5);
+        const doorY = corridorY * scale + (corridorH - doorHeight) / 2;
+        doorways.push({ x: corridorX * scale - 2, y: doorY, width: 4, height: doorHeight }); // left room door
+        doorways.push({ x: corridorX * scale + corridorW - 2, y: doorY, width: 4, height: doorHeight }); // right room door
+      }
+    }
+    // Check vertical adjacency (r1 bottom edge == r2 top edge)
+    else if (Math.abs(r1.y + r1.h - r2.y) < 0.01) {
+      // Horizontal overlap
+      const overlapLeft = Math.max(r1.x, r2.x);
+      const overlapRight = Math.min(r1.x + r1.w, r2.x + r2.w);
+      if (overlapRight > overlapLeft) {
+        const corridorX = overlapLeft;
+        const corridorY = r1.y + r1.h;
+        const corridorW = (overlapRight - overlapLeft) * scale;
+        const corridorH = scale * 8; // corridor height fixed
+        corridors.push({ x: corridorX * scale, y: corridorY * scale, w: corridorW, h: corridorH });
+        // Doorways on both rooms at corridor connection
+        const doorWidth = Math.min(12 * scale, corridorW * 0.5);
+        const doorX = corridorX * scale + (corridorW - doorWidth) / 2;
+        doorways.push({ x: doorX, y: corridorY * scale - 2, width: doorWidth, height: 4 }); // top room door
+        doorways.push({ x: doorX, y: corridorY * scale + corridorH - 2, width: doorWidth, height: 4 }); // bottom room door
+      }
+    }
+  }
+
+  // Connect all adjacent rooms (only pairs once)
+  for (let i = 0; i < rooms.length; i++) {
+    for (let j = i + 1; j < rooms.length; j++) {
+      connectRooms(rooms[i], rooms[j]);
+      connectRooms(rooms[j], rooms[i]);
+    }
+  }
+
+  // Draw corridors
+  ctx.fillStyle = '#555555';
+  for (const c of corridors) {
+    ctx.fillRect(c.x, c.y, c.w, c.h);
+  }
+
+  // Draw rooms
+  for (const room of rooms) {
+    const rx = room.x * scale;
+    const ry = room.y * scale;
+    const rw = room.w * scale;
+    const rh = room.h * scale;
+    // Room fill color based on type
+    const roomColors: Record<CharacterType, string> = {
+      king: '#8b0000', nobility: '#4b0082', knight: '#003366', squire: '#006400',
+      healer: '#2e8b57', sentinel: '#8b4513', scribe: '#483d8b', judge: '#800000', blacksmith: '#555555',
+    };
+    ctx.fillStyle = roomColors[room.type] || '#444444';
+    ctx.fillRect(rx, ry, rw, rh);
+    // Room border
+    ctx.strokeStyle = '#222222';
+    ctx.strokeRect(rx, ry, rw, rh);
+    // Room label
+    ctx.fillStyle = '#eeeeee';
+    ctx.fillText(room.type.toUpperCase(), rx + rw / 2, ry + rh / 2);
+  }
+
+  // Draw doorways
+  ctx.fillStyle = '#d4af37'; // golden door color
+  for (const d of doorways) {
+    ctx.fillRect(d.x, d.y, d.width, d.height);
+  }
+}
+
